from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager, jwt_required, create_access_token, get_raw_jwt
from datetime import timedelta
import secrets

app = Flask(__name__)
app.config['JWT_SECRET_KEY'] = 'super-secret'  # Replace this with your own secret key
jwt = JWTManager(app)

@app.route('/register', methods=['POST'])
def register():
    if not request.json or not 'username' in request.json:
        return jsonify({"msg": "Please provide a username"}), 400

    user = {'id': secrets.token_hex(8), 'username': request.json['username']}
    return jsonify({"msg": "User {} registered successfully.".format(user['username'])}), 201

@app.route('/login', methods=['POST'])
def login():
    if not request.json or not 'username' in request.json:
        return jsonify({"msg": "Please provide a username"}), 400

    user = {'id': secrets.token_hex(8), 'username': request.json['username']}
    access_token = create_access_token(identity=user['id'])
    return jsonify(access_token=access_token)

@app.route('/protected')
@jwt_required()
def protected():
    return jsonify({"msg": "This resource is protected."})

if __name__ == '__main__':
    app.run(debug=True)